const response = $input.first().json;
if (!response.success || !response.clients || response.clients.length === 0) {
  return [];
}
return response.clients.map(client => ({ json: { client_name: client } }));

const clientName = $('Split Client Names').first().json.client_name;
const emails = $input.all();

if (!emails || emails.length === 0) {
  return [{
    json: {
      client_name: clientName,
      email_count: 0,
      emails_text: 'No emails found for this client in the last 24 hours.',
      period_start: new Date(Date.now() - 86400000).toISOString().split('T')[0],
      period_end: new Date().toISOString().split('T')[0]
    }
  }];
}

const periodStart = emails.reduce((min, e) => {
  const d = e.json.date || e.json.created;
  return d < min ? d : min;
}, emails[0].json.date || emails[0].json.created);

const periodEnd = emails.reduce((max, e) => {
  const d = e.json.date || e.json.created;
  return d > max ? d : max;
}, emails[0].json.date || emails[0].json.created);

const emailTexts = emails.map((e, i) => {
  const from = e.json.from?.text || e.json.from || 'Unknown';
  const to = e.json.to?.text || e.json.to || 'Unknown';
  const subject = e.json.subject || 'No Subject';
  const date = e.json.date || e.json.created || 'Unknown Date';
  const body = (e.json.text || e.json.body || '').substring(0, 2000);
  return `EMAIL ${i + 1}\nFrom: ${from}\nTo: ${to}\nDate: ${date}\nSubject: ${subject}\nBody: ${body}`;
}).join('\n\n---\n\n');

return [{
  json: {
    client_name: clientName,
    email_count: emails.length,
    emails_text: emailTexts,
    period_start: typeof periodStart === 'string' ? periodStart.split('T')[0] : new Date(periodStart).toISOString().split('T')[0],
    period_end: typeof periodEnd === 'string' ? periodEnd.split('T')[0] : new Date(periodEnd).toISOString().split('T')[0]
  }
}];

const clientData = $('Compile Email Data').first().json;
const aiSummary = $input.first().json;

const summary = typeof aiSummary === 'string' ? aiSummary : (aiSummary.message?.content || aiSummary.text || JSON.stringify(aiSummary));

return [{
  json: {
    client_name: clientData.client_name,
    summary: summary,
    email_count: clientData.email_count,
    period_start: clientData.period_start,
    period_end: clientData.period_end
  }
}];
